previewCss:
.darma-loader-uiverse-circuit-signal-path { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-circuit-signal-path__trace {
stroke-dasharray: 175;
stroke-dashoffset: 175;
animation: darma-loader-uiverse-circuit-signal-path-circuitDraw 3s linear infinite;
}

/* Stroke "eats" itself forward continuously */
@keyframes darma-loader-uiverse-circuit-signal-path-circuitDraw {
to {
stroke-dashoffset: -175;
}
}

